import numpy as np

def sigmoid(x):
    return 1.0 / (1.0 + np.exp(-x))

def neg_sampling_loss(v_in, v_out_pos, v_out_negs):
    loss = -np.log(sigmoid(np.dot(v_out_pos, v_in)))
    for v_neg in v_out_negs:
        loss -= np.log(sigmoid(-np.dot(v_neg, v_in)))
    return loss

if __name__ == '__main__':
    print('Negative Sampling loss tools ready.')
